import React, { useState, useEffect } from 'react';
import { Menu, X } from 'lucide-react';
import { ViewState } from '../App';

interface HeaderProps {
  onNavigate: (view: ViewState) => void;
  onContactClick: () => void;
  currentView: ViewState;
}

const Header: React.FC<HeaderProps> = ({ onNavigate, onContactClick, currentView }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isDarkBg = currentView === 'home' && !isScrolled;

  const navClasses = `fixed w-full z-50 transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] border-b ${
    isScrolled 
      ? 'bg-white/80 backdrop-blur-md border-gray-100 py-4 text-navy-900 shadow-sm' 
      : 'bg-transparent border-white/10 py-6 text-white'
  }`;

  const finalTextColor = (currentView !== 'home' && !isScrolled) ? 'text-navy-900' : (isScrolled ? 'text-navy-900' : 'text-white');
  const finalNavClasses = (currentView !== 'home' && !isScrolled) ? 'fixed w-full z-50 py-6 bg-white border-b border-gray-100' : navClasses;

  const handleNavClick = (item: string) => {
    setIsMobileMenuOpen(false);

    // Mapping requested menu items to existing view states and anchors
    if (item === 'COMPRAR') onNavigate('buy');
    else if (item === 'VENDER') onNavigate('sell');
    else if (item === 'ALQUILAR') {
        // Placeholder for rental, navigating to buy for now as a luxury boutique alternative
        onNavigate('buy');
    }
    else if (item === 'CREAR') {
        onNavigate('home');
        setTimeout(() => {
             const el = document.getElementById('estudio-ia');
             if (el) el.scrollIntoView({ behavior: 'smooth' });
        }, 100);
    }
    else if (item === 'NOSOTROS') {
        onNavigate('home');
        setTimeout(() => {
             const el = document.getElementById('sobre-nosotros');
             if (el) el.scrollIntoView({ behavior: 'smooth' });
        }, 100);
    }
    else if (item === 'CONTACTO') onContactClick();
    else if (item === 'Home') onNavigate('home');
  };

  const menuItems = ['COMPRAR', 'VENDER', 'ALQUILAR', 'CREAR', 'NOSOTROS', 'CONTACTO'];

  return (
    <header className={finalNavClasses}>
      <div className="container mx-auto px-6 md:px-12 flex justify-between items-center h-full">

        <div 
          className={`hover-trigger text-3xl md:text-4xl font-italiana tracking-tight cursor-pointer ${finalTextColor}`}
          onClick={() => onNavigate('home')}
        >
          lahuerta
        </div>

        <div className="hidden lg:flex items-center space-x-10">
            {menuItems.map((item) => (
                <button 
                    key={item}
                    onClick={() => handleNavClick(item)}
                    className={`hover-trigger text-[10px] font-bold uppercase tracking-[0.2em] hover:opacity-70 transition-opacity ${finalTextColor}`}
                >
                    {item}
                </button>
            ))}
        </div>

        <button 
          className={`hover-trigger p-2 hover:opacity-70 transition-opacity lg:hidden ${finalTextColor}`}
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
           <div className="flex flex-col gap-1.5 items-end">
                <span className={`w-8 h-[1px] bg-current transition-all duration-300 ${isMobileMenuOpen ? 'rotate-45 translate-y-2' : ''}`}></span>
                <span className={`w-6 h-[1px] bg-current transition-all duration-300 ${isMobileMenuOpen ? 'opacity-0' : ''}`}></span>
                <span className={`w-8 h-[1px] bg-current transition-all duration-300 ${isMobileMenuOpen ? '-rotate-45 -translate-y-2' : ''}`}></span>
           </div>
        </button>
      </div>

      <div className={`fixed inset-0 bg-navy-900 z-40 flex flex-col justify-center items-center transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isMobileMenuOpen ? 'opacity-100 visible' : 'opacity-0 invisible pointer-events-none'}`}>
          <div className="absolute top-8 right-8 md:right-12">
             <button onClick={() => setIsMobileMenuOpen(false)} className="hover-trigger text-white hover:opacity-70">
                <X size={32} strokeWidth={1} />
             </button>
          </div>

          <nav className="flex flex-col items-center space-y-8">
            {menuItems.map((item, idx) => (
                <button
                key={item}
                onClick={() => handleNavClick(item)}
                className="hover-trigger text-4xl md:text-5xl text-white font-light tracking-tight hover:text-sand-400 transition-colors duration-300 uppercase"
                style={{ transitionDelay: `${idx * 50}ms` }}
                >
                {item}
                </button>
            ))}
          </nav>
      </div>
    </header>
  );
};

export default Header;

import React, { useEffect, useRef } from 'react';
import { ArrowRight } from 'lucide-react';
import gsap from 'gsap';

const Hero: React.FC = () => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const titleLinesRef = useRef<(HTMLSpanElement | null)[]>([]);
  const textRef = useRef<HTMLParagraphElement>(null);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const topTextRef = useRef<HTMLDivElement>(null);
  const VIDEO_SRC = "/videos/fondocasanovarealestate.mp4"; 

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.defaultMuted = true;
      videoRef.current.muted = true;
      const playPromise = videoRef.current.play();
      if (playPromise !== undefined) playPromise.catch(() => {});
    }

    const ctx = gsap.context(() => {
      gsap.fromTo(topTextRef.current,
        { y: 20, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 0.2 }
      );

      gsap.to(titleLinesRef.current, {
        y: 0,
        opacity: 1,
        duration: 1.5,
        stagger: 0.2,
        ease: "power4.out",
        delay: 0.5 
      });

      gsap.fromTo(textRef.current, 
        { y: 30, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 1.2 }
      );

      gsap.fromTo(buttonRef.current,
        { scale: 0.8, opacity: 0 },
        { scale: 1, opacity: 1, duration: 0.8, ease: "back.out(1.7)", delay: 1.4 }
      );

      gsap.to(videoRef.current, {
        yPercent: 30,
        ease: "none",
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "bottom top",
          scrub: true
        }
      });
    }, containerRef);

    return () => ctx.revert();
  }, []);

  const addToRefs = (el: HTMLSpanElement | null) => {
    if (el && !titleLinesRef.current.includes(el)) {
      titleLinesRef.current.push(el);
    }
  };

  return (
    <section ref={containerRef} className="relative h-screen w-full overflow-hidden bg-navy-900">
      <div className="absolute inset-0 z-0 h-[120%] -top-[10%]">
        <video 
          ref={videoRef}
          key={VIDEO_SRC}
          className="w-full h-full object-cover opacity-80"
          autoPlay loop muted playsInline preload="auto"
        >
          <source src={VIDEO_SRC} type="video/mp4" />
        </video>
        <div className="absolute inset-0 bg-navy-900/20 mix-blend-multiply" />
        <div className="absolute inset-0 bg-gradient-to-t from-navy-900 via-transparent to-transparent opacity-80" />
      </div>

      <div className="relative z-10 container mx-auto px-6 md:px-12 h-full flex flex-col justify-center items-center text-center pb-12">

        <div ref={topTextRef} className="mb-10">
            <span className="text-white/70 text-xs md:text-sm font-bold tracking-[0.5em] uppercase block">
                M A D R I D · E S P A Ñ A
            </span>
        </div>

        <div className="max-w-6xl mx-auto mb-10">
          <h1 className="text-4xl md:text-6xl lg:text-7xl font-serif text-white leading-[1.15] tracking-tight">
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item">Somos la Consultora Inmobiliaria</span>
            </span>
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item">dirigida por arquitectos a la que consultas,</span>
            </span>
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item">antes de tomar una decisión, cuando tu</span>
            </span>
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item italic text-sand-400">objetivo es obtener el máximo valor.</span>
            </span>
          </h1>
        </div>

        <div className="flex flex-col items-center">
            <p ref={textRef} className="text-white/80 text-lg md:text-2xl font-light max-w-3xl leading-relaxed mb-12">
              Expertos en la compra y venta de activos de alto valor en España.
            </p>

            <button 
              ref={buttonRef}
              onClick={() => {
                const el = document.getElementById('sobre-nosotros');
                if (el) el.scrollIntoView({ behavior: 'smooth' });
              }}
              className="hover-trigger bg-white text-navy-900 px-10 py-5 rounded-md flex items-center gap-6 hover:bg-sand-400 transition-all duration-500 group hover:scale-105"
            >
              <span className="text-xs font-bold tracking-[0.3em] uppercase">V E R · P R O P I E D A D E S</span>
              <ArrowRight size={18} className="group-hover:translate-x-2 transition-transform" />
            </button>
        </div>

      </div>
    </section>
  );
};

export default Hero;

import React, { useEffect, useRef } from 'react';
import gsap from 'gsap';

const Services: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const labelRef = useRef<HTMLSpanElement>(null);
  const p1Ref = useRef<HTMLHeadingElement>(null);
  const p2Ref = useRef<HTMLParagraphElement>(null);

  useEffect(() => {
    const ctx = gsap.context(() => {

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top 70%",
        }
      });

      tl.from(labelRef.current, { opacity: 0, y: 20, duration: 0.8 })
        .from(p1Ref.current, { opacity: 0, y: 30, duration: 1, ease: "power3.out" }, "-=0.4")
        .from(p2Ref.current, { opacity: 0, y: 30, duration: 1, ease: "power3.out" }, "-=0.6");

    }, containerRef);

    return () => ctx.revert();
  }, []);

  return (
    <section id="sobre-nosotros" className="bg-white overflow-hidden py-32 md:py-48" ref={containerRef}>
      <div className="container mx-auto px-6 md:px-12">
        <div className="flex flex-col md:flex-row gap-16 lg:gap-32 items-start">

            {/* Left Content Area */}
            <div className="md:w-7/12 lg:w-6/12">
                <span ref={labelRef} className="text-[10px] md:text-xs font-bold uppercase tracking-[0.4em] text-gray-400 mb-12 block">
                    SOBRE NOSOTROS
                </span>

                <h2 ref={p1Ref} className="text-3xl md:text-5xl text-navy-900 font-light leading-snug mb-12">
                    Lahuerta Real Estate es una firma formada por arquitectos y consultores inmobiliarios expertos en ofrecer soluciones creativas y estratégicas para maximizar y potenciar el valor que reciben nuestros clientes en cualquier actuación dentro del sector inmobiliario.
                </h2>

                <p ref={p2Ref} className="text-gray-500 font-light text-lg md:text-xl leading-relaxed max-w-xl">
                    Nuestro equipo combina formación arquitectónica, experiencia técnica y una visión empresarial orientada al negocio, la rentabilidad y el retorno patrimonial con experiencia en proyectos residenciales de alto valor y operaciones de compraventa e inversión en el ámbito nacional.
                </p>
            </div>

            {/* Right Side - Space/Negative Balancing */}
            <div className="md:w-5/12 lg:w-6/12 flex items-center justify-center h-full min-h-[400px]">
                <div className="relative w-full aspect-[4/5] bg-stone-50 rounded-sm overflow-hidden group">
                    <img 
                      src="https://images.unsplash.com/photo-1449156003053-96432b77ec2c?q=80&w=1200&auto=format&fit=crop" 
                      alt="Architecture Detail" 
                      className="w-full h-full object-cover grayscale opacity-40 group-hover:opacity-60 group-hover:scale-105 transition-all duration-1000"
                    />
                    <div className="absolute inset-0 border-[40px] border-white pointer-events-none" />
                </div>
            </div>

        </div>
      </div>
    </section>
  );
};

export default Services;

