  { name: "Comprar", angle: -90 },
  { name: "Diseñar", angle: -18 },
  { name: "Reformar", angle: 54 },
  { name: "Alquilar", angle: 126 },
  { name: "Vender", angle: 198 },
];

const Services: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const [hoveredPoint, setHoveredPoint] = useState<number | null>(null);

  useEffect(() => {
    const ctx = gsap.context(() => {

      // Animate Main Title and Intro
      gsap.from(".services-header > *", {
        scrollTrigger: {
            trigger: ".services-header",
            start: "top 80%",
        },
        y: 40,
        opacity: 0,
        duration: 1,
        stagger: 0.2,
        ease: "power3.out"
      });

      // Pentagon Drawing Animation
      const path = svgRef.current?.querySelector('.pentagon-path') as SVGPathElement;
      if (path) {
        const length = path.getTotalLength();
        gsap.set(path, { strokeDasharray: length, strokeDashoffset: length });

        gsap.to(path, {
          strokeDashoffset: 0,
          duration: 2.5,
          ease: "power2.inOut",
          scrollTrigger: {
            trigger: svgRef.current,
            start: "top 70%",
          }
        });
      }

      // Points and Labels Animation
      gsap.from(".cycle-node", {
        scrollTrigger: {
            trigger: svgRef.current,
            start: "top 70%",
        },
        scale: 0,
        opacity: 0,
        duration: 0.8,
        stagger: 0.2,
        ease: "back.out(1.7)",
        delay: 0.5
      });

      gsap.from(".cycle-label", {
        scrollTrigger: {
            trigger: svgRef.current,
            start: "top 70%",
        },
        y: 10,
        opacity: 0,
        duration: 1,
        stagger: 0.2,
        ease: "power3.out",
        delay: 1
      });

      // Floating dynamic effect for the whole SVG
      gsap.to(svgRef.current, {
        y: 15,
        duration: 4,
        repeat: -1,
        yoyo: true,
        ease: "sine.inOut"
      });

    }, containerRef);

    return () => ctx.revert();
  }, []);

  // Helper to get coordinates for the pentagon vertices
  const getCoords = (angle: number, radius: number) => {
    const radian = (angle * Math.PI) / 180;
    return {
      x: 200 + radius * Math.cos(radian),
      y: 200 + radius * Math.sin(radian)
    };
  };

  const pointsString = cyclePoints
    .map(p => {
      const { x, y } = getCoords(p.angle, 140);
      return `${x},${y}`;
    })
    .join(' ');

  const pathD = `M ${getCoords(cyclePoints[0].angle, 140).x} ${getCoords(cyclePoints[0].angle, 140).y} ` +
    cyclePoints.slice(1).map(p => {
      const { x, y } = getCoords(p.angle, 140);
      return `L ${x} ${y}`;
    }).join(' ') + ' Z';

  return (
    <section id="servicios" className="bg-white overflow-hidden" ref={containerRef}>

      {/* Intro Header */}
      <div className="pt-24 pb-16 container mx-auto px-6 md:px-12">
        <div className="flex flex-col md:flex-row gap-16 items-start services-header">
             <div className="md:w-1/3">
                 <span className="text-xs font-bold uppercase tracking-[0.3em] text-gray-400">NUESTROS SERVICIOS</span>
             </div>
             <div className="md:w-2/3">
                 <h2 className="text-3xl md:text-5xl text-navy-900 font-light leading-tight mb-8">
                    Para comprender el alcance de nuestra propuesta, es esencial visualizar el ciclo integral del inversor.
                 </h2>
             </div>
        </div>
      </div>

      {/* Pentagon Cycle Component */}
      <div className="container mx-auto px-6 md:px-12 mb-32 flex flex-col items-center">
        <div className="relative w-full max-w-[500px] aspect-square">
            <svg 
              ref={svgRef}
              viewBox="0 0 400 400" 
              className="w-full h-full"
            >
                {/* Connection Lines (Background) */}
                <path 
                  d={pathD} 
                  fill="none" 
                  stroke="#f3f3f3" 
                  strokeWidth="1" 
                />

                {/* Animated Drawing Path */}
                <path 
                  className="pentagon-path"
                  d={pathD} 
                  fill="none" 
                  stroke="#A1A1AA" 
                  strokeWidth="1.5"
                  strokeLinecap="round"
                />

                {/* Center Glow */}
                <circle cx="200" cy="200" r="40" fill="url(#centerGradient)" opacity="0.15" />
                <defs>
                  <radialGradient id="centerGradient">
                    <stop offset="0%" stopColor="#A1A1AA" />
                    <stop offset="100%" stopColor="white" />
                  </radialGradient>
                </defs>

                {/* Vertices and Interactive Nodos */}
                {cyclePoints.map((p, i) => {
                  const coords = getCoords(p.angle, 140);
                  const isHovered = hoveredPoint === i;
                  return (
                    <g 
                      key={p.name} 
                      className="cursor-pointer group"
                      onMouseEnter={() => setHoveredPoint(i)}
                      onMouseLeave={() => setHoveredPoint(null)}
                    >
                      {/* Pulse Effect */}
                      <circle 
                        cx={coords.x} 
                        cy={coords.y} 
                        r={isHovered ? 12 : 6} 
                        className="cycle-node fill-white stroke-sand-400 transition-all duration-500"
                        strokeWidth="1"
                      />
                      {isHovered && (
                        <circle 
                          cx={coords.x} 
                          cy={coords.y} 
                          r="18" 
                          className="fill-sand-400 opacity-20 animate-ping"
                        />
                      )}

                      {/* Label Background for Legibility */}
                      <foreignObject 
                        x={coords.x - 60} 
                        y={coords.y > 200 ? coords.y + 20 : coords.y - 45} 
                        width="120" 
                        height="30"
                      >
                        <div className="flex justify-center items-center h-full">
                          <span className={`cycle-label text-[10px] md:text-xs font-bold uppercase tracking-[0.25em] transition-all duration-300 ${isHovered ? 'text-navy-900 scale-110' : 'text-gray-400'}`}>
                            {p.name}
                          </span>
                        </div>
                      </foreignObject>
                    </g>
                  );
                })}
            </svg>

