              <p className="text-2xl md:text-4xl font-serif text-navy-900 leading-tight italic">
                "Aplicamos en cada proyecto de nuestros clientes el mismo rigor y criterio que exigimos para nuestras propias inversiones."
              </p>
            </blockquote>
          </div>
        </div>
      </div>

      {/* Detail Sections (01, 02, 03...) */}
      <div className="flex flex-col">
        {detailedCards.map((step) => (
          <div key={step.id} className="service-item border-t border-gray-100 overflow-hidden last:border-b">
            <div className="container mx-auto px-6 md:px-12 py-32 flex flex-col md:flex-row gap-12 md:gap-24 items-start relative">

              <div className="service-num text-[150px] md:text-[220px] leading-none font-medium text-navy-900/5 select-none absolute left-0 top-0">
                {step.id}
              </div>

              <div className="flex flex-col md:mt-12 flex-1 z-10">
                <span className="service-label text-xs font-bold uppercase tracking-[0.3em] text-sand-500 mb-6 block">
                  {step.label}
                </span>
                <h3 className="service-title text-3xl md:text-5xl text-navy-900 mb-8 font-light max-w-2xl">
                  {step.title}
                </h3>
                <p className="service-desc text-gray-500 font-light text-lg md:text-xl leading-relaxed max-w-2xl mb-12 text-justify">
                  {step.desc}
                </p>
                <div className="service-img-wrapper w-full aspect-[21/9] overflow-hidden rounded-sm bg-gray-50">
                  <img 
                    src={step.image} 
                    alt={step.title} 
                    className="w-full h-full object-cover grayscale opacity-80 hover:grayscale-0 hover:opacity-100 transition-all duration-1000"
                  />
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Services;

